 10→import { toIsoString } from "../http/response";
 11→import { logInfo } from "../http/observability";
 12→
 13→// ── Pure functions (exported for unit testing) ──────────────────────────
 14→
 15→export type TouchedByEdge = {
 16→  projectId: string;
 17→  conversationId: string;
 18→  entityCount: number;
 19→  firstMentionAt: string;
 20→};
 21→
 22→export type ConversationGroupInput = {
 23→  id: string;
 24→  title?: string;
 25→  updatedAt: string;
 26→  touchedBy: Array<{ projectId: string; entityCount: number }>;
 27→};
 28→
 29→export type GroupingResult = {
 30→  groups: Map<string, ConversationSidebarItem[]>;
 31→  unlinked: ConversationSidebarItem[];
 32→};
 33→
 34→/**
 35→ * Groups conversations by dominant project using strict majority heuristic.
 36→ * A conversation is assigned to a project only if that project's entity_count
 37→ * is strictly greater than half of the total entity count across all projects.
 38→ */
 39→export function groupConversationsByProject(conversations: ConversationGroupInput[]): GroupingResult {
 40→  const groups = new Map<string, ConversationSidebarItem[]>();
 41→  const unlinked: ConversationSidebarItem[] = [];
 42→
 43→  for (const conv of conversations) {
 44→    const item: ConversationSidebarItem = {
 45→      id: conv.id,
 46→      title: conv.title ?? "Untitled",
 47→      updatedAt: conv.updatedAt,
 48→    };
 49→
 50→    if (conv.touchedBy.length === 0) {
 51→      unlinked.push(item);
 52→      continue;
 53→    }
 54→
 55→    const total = conv.touchedBy.reduce((sum, edge) => sum + edge.entityCount, 0);
 56→    let topEdge = conv.touchedBy[0];
 57→    for (const edge of conv.touchedBy) {
 58→      if (edge.entityCount > topEdge.entityCount) {
 59→        topEdge = edge;
 60→      }
 61→    }
 62→
 63→    if (topEdge.entityCount > total / 2) {
 64→      const existing = groups.get(topEdge.projectId) ?? [];
 65→      existing.push(item);
 66→      groups.set(topEdge.projectId, existing);
 67→    } else {
 68→      unlinked.push(item);
 69→    }
 70→  }
 71→
 72→  return { groups, unlinked };
 73→}
 74→
 75→/**
 76→ * Derives the initial title for a conversation from the first user message.
 77→ */
 78→export function deriveMessageTitle(text: string): string {
 79→  const trimmed = text.trim();
 80→  if (trimmed.length <= 72) {
 81→    return trimmed;
 82→  }
 83→  return `${trimmed.slice(0, 69)}...`;
 84→}
 85→
 86→export type TitleUpgradeInput = {
 87→  titleSource?: "message" | "entity";
 88→  entityTexts: Array<{ kind: string; text: string }>;
 89→  dominantProjectName?: string;
 90→};
 91→
 92→/**
 93→ * Determines whether a conversation title should be upgraded and returns
 94→ * the new title if so. Returns undefined if no upgrade should happen.
 95→ */
 96→export function computeTitleUpgrade(input: TitleUpgradeInput): string | undefined {
 97→  if (input.titleSource !== "message") {
 98→    return undefined;
 99→  }
100→
101→  const qualifying = input.entityTexts.filter(
102→    (entity) => entity.kind !== "person" && entity.kind !== "workspace",
103→  );
104→
105→  if (qualifying.length < 3) {
106→    return undefined;
107→  }
108→
109→  if (input.dominantProjectName) {
110→    return deriveMessageTitle(input.dominantProjectName);
111→  }
112→
113→  // Use the most common entity text as fallback
114→  const counts = new Map<string, number>();
115→  for (const entity of qualifying) {
116→    const key = entity.text.toLowerCase();
117→    counts.set(key, (counts.get(key) ?? 0) + 1);
118→  }
119→
120→  let bestText = qualifying[0].text;
121→  let bestCount = 0;
122→  for (const [key, count] of counts) {
123→    if (count > bestCount) {
124→      bestCount = count;
125→      bestText = qualifying.find((e) => e.text.toLowerCase() === key)?.text ?? bestText;
126→    }
127→  }
128→
129→  return deriveMessageTitle(bestText);
130→}
131→
132→// ── Entity-to-project resolution ────────────────────────────────────────
133→
134→type ExtractionEdgeRow = {
135→  out: GraphEntityRecord;
136→  extracted_at: Date | string;
137→};
138→
139→type BelongsToRow = {
140→  out: RecordId<string, string> & { tb: string };
141→};
142→
143→type HasFeatureRow = {
144→  in: RecordId<"project", string>;
145→};
146→
147→/**
148→ * Resolves which project(s) an extracted entity belongs to.
149→ * Returns a map of projectId -> { entityIds, earliestExtractedAt }.
150→ */
151→async function resolveEntityToProjects(
152→  surreal: Surreal,
153→  entityRecord: GraphEntityRecord,
154→): Promise<RecordId<"project", string>[]> {
155→  const table = entityRecord.tb;
156→
157→  if (table === "project") {
158→    return [entityRecord as unknown as RecordId<"project", string>];
159→  }
160→
161→  if (table === "feature") {
162→    const [rows] = await surreal
163→      .query<[HasFeatureRow[]]>(
164→        "SELECT `in` FROM has_feature WHERE out = $feature;",
165→        { feature: entityRecord },
166→      )
167→      .collect<[HasFeatureRow[]]>();
168→    return rows.map((row) => row.in);
169→  }
170→
171→  if (table === "task" || table === "decision" || table === "question") {
172→    const [belongsToRows] = await surreal
173→      .query<[BelongsToRow[]]>(
174→        "SELECT out FROM belongs_to WHERE `in` = $entity;",
175→        { entity: entityRecord },
176→      )
177→      .collect<[BelongsToRow[]]>();
178→
179→    const projects: RecordId<"project", string>[] = [];
180→
181→    for (const row of belongsToRows) {
182→      if (row.out.tb === "project") {
183→        projects.push(row.out as RecordId<"project", string>);
184→      } else if (row.out.tb === "feature") {
185→        const [featureRows] = await surreal
186→          .query<[HasFeatureRow[]]>(
187→            "SELECT `in` FROM has_feature WHERE out = $feature;",
188→            { feature: row.out },
189→          )
190→          .collect<[HasFeatureRow[]]>();
191→        projects.push(...featureRows.map((r) => r.in));
192→      }
193→    }
194→
195→    return projects;
196→  }
197→
198→  // person, workspace, and other kinds do not contribute
199→  return [];
200→}
201→
202→// ── Database operations ─────────────────────────────────────────────────
203→
204→type TouchedByRow = {
205→  id: RecordId<"touched_by", string>;
206→  in: RecordId<"project", string>;
207→  out: RecordId<"conversation", string>;
208→  entity_count: number;
209→  first_mention_at: Date | string;
210→};
211→
212→/**
213→ * Refreshes the touched_by edges for a conversation based on its extraction_relation rows.
214→ */
215→export async function refreshConversationTouchedBy(
216→  surreal: Surreal,
217→  conversationRecord: RecordId<"conversation", string>,
218→): Promise<void> {
219→  const [extractionRows] = await surreal
220→    .query<[ExtractionEdgeRow[]]>(
221→      "SELECT out, extracted_at FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
222→      { conversation: conversationRecord },
223→    )
224→    .collect<[ExtractionEdgeRow[]]>();
225→
226→  // Aggregate: projectId -> { uniqueEntityIds, earliestExtractedAt }
227→  const projectAgg = new Map<string, { entityIds: Set<string>; earliestAt: Date }>();
228→
229→  for (const row of extractionRows) {
230→    const projects = await resolveEntityToProjects(surreal, row.out);
231→    const extractedAt = row.extracted_at instanceof Date ? row.extracted_at : new Date(row.extracted_at as string);
232→    const entityId = `${row.out.tb}:${row.out.id}`;
233→
234→    for (const projectRecord of projects) {
235→      const projectId = projectRecord.id as string;
236→      const existing = projectAgg.get(projectId);
237→      if (existing) {
238→        existing.entityIds.add(entityId);
239→        if (extractedAt < existing.earliestAt) {
240→          existing.earliestAt = extractedAt;
241→        }
242→      } else {
243→        projectAgg.set(projectId, {
244→          entityIds: new Set([entityId]),
245→          earliestAt: extractedAt,
246→        });
247→      }
248→    }
249→  }
250→
251→  // Load existing touched_by edges for this conversation
252→  const [existingEdges] = await surreal
253→    .query<[TouchedByRow[]]>(
254→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out = $conversation;",
255→      { conversation: conversationRecord },
256→    )
257→    .collect<[TouchedByRow[]]>();
258→
259→  const existingByProject = new Map<string, TouchedByRow>();
260→  for (const edge of existingEdges) {
261→    existingByProject.set(edge.in.id as string, edge);
262→  }
263→
264→  // Upsert edges for current project aggregations
265→  for (const [projectId, agg] of projectAgg) {
266→    const existing = existingByProject.get(projectId);
267→    const entityCount = agg.entityIds.size;
268→
269→    if (existing) {
270→      await surreal.update(existing.id).merge({
271→        entity_count: entityCount,
272→        first_mention_at: agg.earliestAt,
273→      });
274→      existingByProject.delete(projectId);
275→    } else {
276→      const projectRecord = new RecordId("project", projectId);
277→      await surreal.relate(
278→        projectRecord,
279→        new RecordId("touched_by", randomUUID()),
280→        conversationRecord,
281→        {
282→          first_mention_at: agg.earliestAt,
283→          entity_count: entityCount,
284→        },
285→      ).output("after");
286→    }
287→  }
288→
289→  // Remove stale edges (projects no longer represented)
290→  for (const staleEdge of existingByProject.values()) {
291→    await surreal.delete(staleEdge.id);
292→  }
293→
294→  logInfo("conversation.touched_by.refreshed", "Refreshed touched_by edges", {
295→    conversationId: conversationRecord.id as string,
296→    projectCount: projectAgg.size,
297→    removedCount: existingByProject.size,
298→  });
299→}
300→
301→/**
302→ * Upgrades a conversation title if conditions are met (title_source === "message",
303→ * >= 3 qualifying entities extracted).
304→ */
305→export async function maybeUpgradeConversationTitle(
306→  surreal: Surreal,
307→  conversationRecord: RecordId<"conversation", string>,
308→): Promise<void> {
309→  const conversation = await surreal.select<{
310→    title?: string;
311→    title_source?: "message" | "entity";
312→  }>(conversationRecord);
313→
314→  if (!conversation || conversation.title_source !== "message") {
315→    return;
316→  }
317→
318→  // Count qualifying extracted entities for this conversation
319→  const [entityRows] = await surreal
320→    .query<[Array<{ out: GraphEntityRecord }>]>(
321→      "SELECT out FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
322→      { conversation: conversationRecord },
323→    )
324→    .collect<[Array<{ out: GraphEntityRecord }>]>();
325→
326→  const uniqueEntities = new Map<string, { kind: string; text: string }>();
327→  for (const row of entityRows) {
328→    const key = `${row.out.tb}:${row.out.id}`;
329→    if (!uniqueEntities.has(key)) {
330→      uniqueEntities.set(key, { kind: row.out.tb, text: "" });
331→    }
332→  }
333→
334→  const qualifying = [...uniqueEntities.values()].filter(
335→    (e) => e.kind !== "person" && e.kind !== "workspace",
336→  );
337→
338→  if (qualifying.length < 3) {
339→    return;
340→  }
341→
342→  // Check for dominant project via touched_by
343→  const [touchedByRows] = await surreal
344→    .query<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>(
345→      "SELECT `in`, entity_count FROM touched_by WHERE out = $conversation;",
346→      { conversation: conversationRecord },
347→    )
348→    .collect<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>();
349→
350→  let dominantProjectName: string | undefined;
351→  if (touchedByRows.length > 0) {
352→    const total = touchedByRows.reduce((sum, row) => sum + row.entity_count, 0);
353→    let topRow = touchedByRows[0];
354→    for (const row of touchedByRows) {
355→      if (row.entity_count > topRow.entity_count) {
356→        topRow = row;
357→      }
358→    }
359→
360→    if (topRow.entity_count > total / 2) {
361→      const project = await surreal.select<{ name: string }>(topRow.in);
362→      if (project) {
363→        dominantProjectName = project.name;
364→      }
365→    }
366→  }
367→
368→  // Get entity texts for fallback title
369→  const entityTexts: Array<{ kind: string; text: string }> = [];
370→  for (const [, entry] of uniqueEntities) {
371→    entityTexts.push(entry);
372→  }
373→
374→  // Need actual texts from entities
375→  const entityTextRows: Array<{ kind: string; text: string }> = [];
376→  for (const row of entityRows) {
377→    const kind = row.out.tb;
378→    if (kind === "person" || kind === "workspace") continue;
379→
380→    const textField = kind === "task" ? "title" : kind === "decision" ? "summary" : "text";
381→    const entity = await surreal.select<Record<string, string>>(row.out);
382→    if (entity) {
383→      const text = entity[textField] ?? entity.name ?? "";
384→      entityTextRows.push({ kind, text });
385→    }
386→  }
387→
388→  const newTitle = computeTitleUpgrade({
389→    titleSource: "message",
390→    entityTexts: entityTextRows,
391→    dominantProjectName,
392→  });
393→
394→  if (newTitle) {
395→    await surreal.update(conversationRecord).merge({
396→      title: newTitle,
397→      title_source: "entity" as const,
398→    });
399→
400→    logInfo("conversation.title.upgraded", "Upgraded conversation title", {
401→      conversationId: conversationRecord.id as string,
402→      newTitle,
403→    });
404→  }
405→}
406→
407→// ── Sidebar builder ─────────────────────────────────────────────────────
408→
409→type ConversationSidebarRow = {
410→  id: RecordId<"conversation", string>;
411→  title?: string;
412→  updatedAt: Date | string;
413→};
414→
415→type FeatureActivityRow = {
416→  featureId: RecordId<"feature", string>;
417→  featureName: string;
418→  latestActivityAt: Date | string;
419→};
420→
421→export async function buildWorkspaceConversationSidebar(
422→  surreal: Surreal,
423→  workspaceRecord: RecordId<"workspace", string>,
424→): Promise<WorkspaceConversationSidebarResponse> {
425→  // Load all conversations for this workspace
426→  const [conversationRows] = await surreal
427→    .query<[ConversationSidebarRow[]]>(
428→      "SELECT id, title, updatedAt FROM conversation WHERE workspace = $workspace ORDER BY updatedAt DESC;",
429→      { workspace: workspaceRecord },
430→    )
431→    .collect<[ConversationSidebarRow[]]>();
432→
433→  // Load all touched_by edges for these conversations
434→  const conversationIds = conversationRows.map((row) => row.id);
435→  const [touchedByRows] = await surreal
436→    .query<[TouchedByRow[]]>(
437→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out IN $conversations;",
438→      { conversations: conversationIds },
439→    )
440→    .collect<[TouchedByRow[]]>();
441→
442→  // Build touched_by lookup by conversation
443→  const touchedByMap = new Map<string, Array<{ projectId: string; entityCount: number }>>();
444→  for (const row of touchedByRows) {
445→    const convId = row.out.id as string;
446→    const existing = touchedByMap.get(convId) ?? [];
447→    existing.push({ projectId: row.in.id as string, entityCount: row.entity_count });
448→    touchedByMap.set(convId, existing);
449→  }
450→
451→  // Build conversation input for grouping
452→  const conversationInputs: ConversationGroupInput[] = conversationRows.map((row) => ({
453→    id: row.id.id as string,
454→    title: row.title,
455→    updatedAt: toIsoString(row.updatedAt),
456→    touchedBy: touchedByMap.get(row.id.id as string) ?? [],
457→  }));
458→
459→  const { groups, unlinked } = groupConversationsByProject(conversationInputs);
460→
461→  // Load project names and build groups
462→  const projectGroups: ProjectConversationGroup[] = [];
463→  for (const [projectId, conversations] of groups) {
464→    const projectRecord = new RecordId("project", projectId);
465→    const project = await surreal.select<{ name: string }>(projectRecord);
466→    if (!project) continue;
467→
468→    const featureActivity = await loadProjectFeatureActivity(surreal, projectRecord, conversations);
469→
470→    projectGroups.push({
471→      projectId,
472→      projectName: project.name,
473→      conversations,
474→      featureActivity,
475→    });
476→  }
477→
478→  return { groups: projectGroups, unlinked };
479→}
480→
481→async function loadProjectFeatureActivity(
482→  surreal: Surreal,
483→  projectRecord: RecordId<"project", string>,
484→  _conversations: ConversationSidebarItem[],
485→): Promise<ProjectFeatureActivity[]> {
486→  // Get features for this project with latest extraction activity
487→  const [rows] = await surreal
488→    .query<[FeatureActivityRow[]]>(
489→      [
490→        "SELECT out.id AS featureId, out.name AS featureName, math::max(extracted_at) AS latestActivityAt",
491→        "FROM extraction_relation",
492→        "WHERE out IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
493→        "GROUP BY out",
494→        "ORDER BY latestActivityAt DESC",
495→        "LIMIT 5;",
496→      ].join(" "),
497→      { project: projectRecord },
498→    )
499→    .collect<[FeatureActivityRow[]]>();
500→
501→  return rows.map((row) => ({
502→    featureId: (row.featureId as unknown as RecordId<"feature", string>).id as string,
503→    featureName: row.featureName,
504→    latestActivityAt: toIsoString(row.latestActivityAt),
505→  }));
506→}
