543→    let streamedText = "";
544→
545→    const stream = new EventSource(payload.streamUrl);
546→    streamRef.current = stream;
547→
548→    stream.onmessage = (messageEvent) => {
549→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
550→
551→      if (parsed.type === "token") {
552→        streamedText = `${streamedText}${parsed.token}`;
553→        setSessions((existing) =>
554→          existing.map((session) =>
555→            session.id === activeSessionId
556→              ? {
557→                  ...session,
558→                  conversations: session.conversations.map((conversation) =>
559→                    conversation.id === clientMessageId
560→                      ? {
561→                          ...conversation,
562→                          response: streamedText,
563→                          updatedAt: new Date(),
564→                        }
565→                      : conversation,
566→                  ),
567→                }
568→              : session,
569→          ),
570→        );
571→        return;
572→      }
573→
574→      if (parsed.type === "extraction") {
575→        setSeedItems((existing) => {
576→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
577→          for (const entity of parsed.entities) {
578→            const key = `${entity.id}:${entity.sourceKind}:${entity.sourceId}`;
579→            if (!deduped.has(key)) {
580→              deduped.set(key, {
581→                id: entity.id,
582→                kind: entity.kind,
583→                text: entity.text,
584→                confidence: entity.confidence,
585→                sourceKind: entity.sourceKind,
586→                sourceId: entity.sourceId,
587→              });
588→            }
589→          }
590→          return [...deduped.values()];
591→        });
592→        return;
593→      }
594→
595→      if (parsed.type === "assistant_message") {
596→        streamedText = parsed.text;
597→        setSuggestions(
598→          (parsed.suggestions ?? []).map((content, index) => ({
599→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
600→            content,
601→          })),
602→        );
603→        setSessions((existing) =>
604→          existing.map((session) =>
605→            session.id === activeSessionId
606→              ? {
607→                  ...session,
608→                  conversations: session.conversations.map((conversation) =>
609→                    conversation.id === clientMessageId
610→                      ? {
611→                          ...conversation,
612→                          response: streamedText,
613→                          updatedAt: new Date(),
614→                        }
615→                      : conversation,
616→                  ),
617→                }
618→              : session,
619→          ),
620→        );
621→        return;
622→      }
623→
624→      if (parsed.type === "onboarding_seed") {
625→        setSeedItems((existing) => {
626→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
627→          for (const seed of parsed.seeds) {
628→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
629→          }
630→          return [...deduped.values()];
631→        });
632→        return;
633→      }
634→
635→      if (parsed.type === "onboarding_state") {
636→        setWorkspace((existing) =>
637→          existing
638→            ? {
639→                ...existing,
640→                onboardingState: parsed.onboardingState,
641→                onboardingComplete: parsed.onboardingState === "complete",
642→              }
643→            : existing,
644→        );
645→        return;
646→      }
647→
648→      if (parsed.type === "error") {
649→        setErrorMessage(parsed.error);
650→        setIsLoading(false);
651→        stream.close();
652→        streamRef.current = undefined;
653→        return;
654→      }
655→
656→      if (parsed.type === "done") {
657→        setSessions((existing) =>
658→          existing.map((session) =>
659→            session.id === activeSessionId
660→              ? {
661→                  ...session,
662→                  updatedAt: new Date(),
663→                  conversations: session.conversations.map((conversation) =>
664→                    conversation.id === clientMessageId
665→                      ? {
666→                          ...conversation,
667→                          response: streamedText,
668→                          updatedAt: new Date(),
669→                        }
670→                      : conversation,
671→                  ),
672→                }
673→              : session,
674→          ),
675→        );
676→
677→        setIsLoading(false);
678→        stream.close();
679→        streamRef.current = undefined;
680→
681→        // Refresh sidebar after stream completes
682→        if (workspace) {
683→          void refreshSidebar(workspace.id);
684→        }
685→      }
686→    };
687→
688→    stream.onerror = () => {
689→      setErrorMessage("SSE stream disconnected");
690→      setIsLoading(false);
691→      stream.close();
692→      streamRef.current = undefined;
693→    };
694→  }
695→
696→  function onStopMessage() {
697→    if (!streamRef.current) {
698→      return;
699→    }
700→
701→    streamRef.current.close();
702→    streamRef.current = undefined;
703→    setIsLoading(false);
704→  }
705→
706→  if (!workspace) {
707→    return (
708→      <section className="workspace-setup">
709→        <h2>Create Workspace</h2>
710→        <p>Start with workspace name and owner identity. Onboarding continues in chat.</p>
711→        <form onSubmit={onCreateWorkspace} className="workspace-form">
712→          <label>
713→            Workspace name
714→            <input
715→              value={createWorkspaceName}
716→              onChange={(event) => setCreateWorkspaceName(event.target.value)}
717→              placeholder="Acme Labs"
718→              required
719→            />
720→          </label>
721→          <label>
722→            Owner display name
723→            <input
724→              value={createOwnerName}
725→              onChange={(event) => setCreateOwnerName(event.target.value)}
726→              placeholder="Marcus"
727→              required
728→            />
729→          </label>
730→          <button type="submit" disabled={!canCreateWorkspace || isCreatingWorkspace || isBootstrapping}>
731→            {isCreatingWorkspace ? "Creating..." : "Create Workspace"}
732→          </button>
733→        </form>
734→        {errorMessage ? <p className="error-message">{errorMessage}</p> : undefined}
735→      </section>
736→    );
737→  }
738→
739→  return (
740→    <section className="reachat-page">
741→      <div className="workspace-toolbar">
742→        <div>
743→          <strong>{workspace.name}</strong>
744→        </div>
745→        <button type="button" className="seed-toggle" onClick={() => setIsSeedPanelOpen((current) => !current)}>
746→          {isSeedPanelOpen ? "Hide live graph seed" : "Show live graph seed"} ({seedItems.length})
747→        </button>
748→        {pendingFile ? (
749→          <div className="pending-file">
750→            Attached: {pendingFile.name}
751→            <button type="button" onClick={() => setPendingFile(undefined)}>
752→              Clear
753→            </button>
754→          </div>
755→        ) : undefined}
756→      </div>
757→
758→      <div className="workspace-layout">
759→        <aside className="conversation-sidebar">
760→          <button
761→            type="button"
762→            className="sidebar-new-conversation"
763→            onClick={onNewConversation}
764→            disabled={isLoading}
765→          >
766→            New conversation
767→          </button>
768→
769→          {sidebar?.groups.map((group) => (
770→            <div key={group.projectId} className="sidebar-project-group">
771→              <div className="sidebar-project-header">
772→                <span className="sidebar-project-name">{group.projectName}</span>
773→                <span className="sidebar-project-count">{group.conversations.length}</span>
774→              </div>
775→              {group.featureActivity.length > 0 ? (
776→                <div className="sidebar-feature-activity">
777→                  {group.featureActivity.map((feature) => (
778→                    <span key={feature.featureId} className="sidebar-feature-chip">
779→                      {feature.featureName}
780→                    </span>
781→                  ))}
782→                </div>
783→              ) : undefined}
784→              <ul className="sidebar-conversation-list">
785→                {group.conversations.map((conv) => (
786→                  <li key={conv.id}>
787→                    <button
788→                      type="button"
789→                      className={`sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-conversation-item--active" : ""}`}
790→                      onClick={() => onSelectConversation(conv.id)}
791→                    >
792→                      {conv.title}
793→                    </button>
794→                  </li>
795→                ))}
796→              </ul>
797→            </div>
798→          ))}
799→
800→          {sidebar && sidebar.unlinked.length > 0 ? (
801→            <div className="sidebar-project-group">
802→              <div className="sidebar-project-header">
803→                <span className="sidebar-project-name sidebar-unlinked-label">Unlinked</span>
804→                <span className="sidebar-project-count">{sidebar.unlinked.length}</span>
805→              </div>
806→              <ul className="sidebar-conversation-list">
807→                {sidebar.unlinked.map((conv) => (
808→                  <li key={conv.id}>
809→                    <button
810→                      type="button"
811→                      className={`sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-conversation-item--active" : ""}`}
812→                      onClick={() => onSelectConversation(conv.id)}
813→                    >
814→                      {conv.title}
815→                    </button>
816→                  </li>
817→                ))}
818→              </ul>
819→            </div>
820→          ) : undefined}
821→        </aside>
822→
823→        <div className={`chat-main${isSeedPanelOpen ? " chat-main--with-seeds" : ""}`}>
824→          <Chat
825→            viewType="chat"
826→            sessions={sessions}
827→            activeSessionId={activeSession.id}
828→            components={chatComponentCatalog}
829→            isLoading={isLoading}
830→            onSendMessage={onSendMessage}
831→            onStopMessage={onStopMessage}
832→            onFileUpload={onUploadFile}
833→          >
834→            <SessionMessagePanel>
835→              <SessionMessagesHeader>
836→                <div className="reachat-header">Workspace Chat + Extraction</div>
837→              </SessionMessagesHeader>
838→              <SessionMessages>
839→                {(conversations) =>
840→                  conversations.map((conversation, index) => (
841→                    <div key={conversation.id} data-message-id={conversation.id}>
842→                      <SessionMessage
843→                        conversation={conversation}
844→                        isLast={index === conversations.length - 1}
845→                      />
846→                    </div>
847→                  ))
848→                }
849→              </SessionMessages>
850→              <ChatSuggestions
851→                suggestions={suggestions}
852→                onSuggestionClick={(suggestion) => {
853→                  void onSendMessage(suggestion);
854→                }}
855→              />
856→              {workspace.onboardingState === "summary_pending" ? (
857→                <div className="onboarding-action-buttons">
858→                  <button
859→                    type="button"
860→                    disabled={isLoading}
861→                    onClick={() =>
862→                      void onSendMessage("Looks good, let's go.", {
863→                        onboardingAction: "finalize_onboarding",
864→                      })}
865→                  >
866→                    Looks good, let's go
867→                  </button>
868→                  <button
869→                    type="button"
870→                    disabled={isLoading}
871→                    onClick={() =>
872→                      void onSendMessage("I want to add more.", {
873→                        onboardingAction: "continue_onboarding",
874→                      })}
875→                  >
876→                    I want to add more
877→                  </button>
878→                </div>
879→              ) : undefined}
880→              <div onClickCapture={onChatInputClickCapture}>
881→                <ChatInput
882→                  ref={chatInputRef}
883→                  placeholder="Discuss tasks, decisions, and questions..."
884→                  allowedFiles={[".md", ".txt"]}
885→                  mentions={{
886→                    onSearch: searchMentions,
887→                  }}
888→                  commands={{
889→                    items: COMMAND_ITEMS,
890→                  }}
891→                />
892→              </div>
893→            </SessionMessagePanel>
894→          </Chat>
895→
896→          {isSeedPanelOpen ? (
897→            <aside className="seed-panel">
898→              <h3>Live Graph Seed</h3>
899→              <p>Entities extracted during onboarding and document ingestion.</p>
900→              <ul>
901→                {seedItems.map((seed) => (
902→                  <li key={`${seed.id}:${seed.sourceKind}:${seed.sourceId}`}>
903→                    <button
904→                      type="button"
905→                    >
