  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import type {
  4→  CreateWorkspaceResponse,
  5→  OnboardingSeedItem,
  6→  WorkspaceBootstrapMessage,
  7→  WorkspaceBootstrapResponse,
  8→  WorkspaceConversationResponse,
  9→  SourceKind,
 10→  EntityKind,
 11→} from "../../shared/contracts";
 12→import { createEmbeddingVector } from "../graph/embeddings";
 13→import { readEntityText } from "../extraction/entity-text";
 14→import type { GraphEntityRecord, SourceRecord } from "../extraction/types";
 15→import { HttpError } from "../http/errors";
 16→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
 17→import { parseCreateWorkspaceRequest } from "../http/parsing";
 18→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 19→import type { ServerDependencies } from "../runtime/types";
 20→import { toOnboardingState } from "../onboarding/onboarding-state";
 21→import { resolveWorkspaceRecord } from "./workspace-scope";
 22→import { buildWorkspaceConversationSidebar } from "./conversation-sidebar";
 23→
 24→type WorkspaceRow = {
 25→  id: RecordId<"workspace", string>;
 26→  name: string;
 27→  status: string;
 28→  onboarding_complete: boolean;
 29→  onboarding_turn_count: number;
 30→  onboarding_summary_pending: boolean;
 31→};
 32→
 33→type MessageContextRow = {
 34→  id: RecordId<"message", string>;
 35→  role: "user" | "assistant";
 36→  text: string;
 37→  createdAt: Date | string;
 38→  suggestions?: string[];
 39→};
 40→
 41→type ProvenanceEdgeRow = {
 42→  id: RecordId<"extraction_relation", string>;
 43→  in: SourceRecord;
 44→  out: GraphEntityRecord;
 45→  confidence: number;
 46→  extracted_at: Date | string;
 47→};
 48→
 49→export function createWorkspaceRouteHandlers(deps: ServerDependencies): {
 50→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 51→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 52→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 53→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 54→} {
 55→  return {
 56→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 57→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 58→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 59→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 60→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 61→  };
 62→}
 63→
 64→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 65→  const startedAt = performance.now();
 66→  logInfo("workspace.create.started", "Workspace creation started");
 67→
 68→  let body: unknown;
 69→  try {
 70→    body = await request.json();
 71→  } catch {
 72→    return jsonError("Request body must be valid JSON", 400);
 73→  }
 74→
 75→  const parsed = parseCreateWorkspaceRequest(body);
 76→  if (!parsed.ok) {
 77→    return jsonError(parsed.error, 400);
 78→  }
 79→
 80→  logDebug("http.request.validated", "Workspace request validated");
 81→
 82→  const now = new Date();
 83→  const workspaceId = randomUUID();
 84→  const conversationId = randomUUID();
 85→  const ownerId = randomUUID();
 86→
 87→  const workspaceRecord = new RecordId("workspace", workspaceId);
 88→  const conversationRecord = new RecordId("conversation", conversationId);
 89→  const ownerRecord = new RecordId("person", ownerId);
 90→  const starterMessageRecord = new RecordId("message", randomUUID());
 91→  const starterSuggestions = [
 92→    "Describe your primary project and goal",
 93→    "Share the biggest current bottleneck",
 94→    "Upload a plan or spec to extract",
 95→  ];
 96→
 97→  const starterMessage = [
 98→    `Hey ${parsed.data.ownerDisplayName}!`,
 99→    "I'm ready to help you build out your workspace.",
100→    "Tell me about what you're working on - what's the main project or business you want to track here?",
101→    "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
102→  ].join(" ");
103→
104→  const transaction = await deps.surreal.beginTransaction();
105→  try {
106→    await transaction.create(workspaceRecord).content({
107→      name: parsed.data.name,
108→      status: "active",
109→      onboarding_complete: false,
110→      onboarding_turn_count: 0,
111→      onboarding_summary_pending: false,
112→      onboarding_started_at: now,
113→      created_at: now,
114→      updated_at: now,
115→    });
116→
117→    const ownerEmbedding = await createEmbeddingVector(
118→      deps.embeddingModel,
119→      parsed.data.ownerDisplayName,
120→      deps.config.embeddingDimension,
121→    );
122→    await transaction.create(ownerRecord).content({
123→      name: parsed.data.ownerDisplayName,
124→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
125→      created_at: now,
126→      updated_at: now,
127→    });
128→
129→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
130→      role: "owner",
131→      added_at: now,
132→    }).output("after");
133→
134→    await transaction.create(conversationRecord).content({
135→      createdAt: now,
136→      updatedAt: now,
137→      workspace: workspaceRecord,
138→      source: "onboarding",
139→      title: "Onboarding",
140→      title_source: "message",
141→    });
142→
143→    await transaction.create(starterMessageRecord).content({
144→      conversation: conversationRecord,
145→      role: "assistant",
146→      text: starterMessage,
147→      suggestions: starterSuggestions,
148→      createdAt: now,
149→    });
150→
151→    await transaction.commit();
152→  } catch (error) {
153→    await transaction.cancel();
154→    logError("workspace.create.failed", "Workspace creation failed", error, {
155→      workspaceId,
156→      conversationId,
157→    });
158→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
159→    return jsonError(errorText, 500);
160→  }
161→
162→  const response: CreateWorkspaceResponse = {
163→    workspaceId,
164→    workspaceName: parsed.data.name,
165→    conversationId,
166→    onboardingComplete: false,
167→  };
168→
169→  logInfo("workspace.create.completed", "Workspace creation completed", {
170→    workspaceId,
171→    conversationId,
172→    durationMs: elapsedMs(startedAt),
173→  });
174→
175→  return jsonResponse(response, 200);
176→}
177→
178→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
179→  const startedAt = performance.now();
180→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
181→
182→  try {
183→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
184→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
185→    if (!workspace) {
186→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
187→    }
188→
189→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
190→    const [messageRows] = await deps.surreal
191→      .query<[MessageContextRow[]]>(
192→        "SELECT id, role, text, createdAt, suggestions FROM message WHERE conversation = $conversation ORDER BY createdAt ASC LIMIT 80;",
193→        {
194→          conversation: conversationRecord,
195→        },
196→      )
197→      .collect<[MessageContextRow[]]>();
198→
199→    const messages = messageRows.map((row) => ({
200→      id: row.id.id as string,
201→      role: row.role,
202→      text: row.text,
203→      createdAt: toIsoString(row.createdAt),
204→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
205→    } satisfies WorkspaceBootstrapMessage));
206→
207→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
208→    const onboardingState = toOnboardingState(workspace);
209→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
210→
211→    const payload: WorkspaceBootstrapResponse = {
212→      workspaceId: workspace.id.id as string,
213→      workspaceName: workspace.name,
214→      onboardingComplete: workspace.onboarding_complete,
215→      onboardingState,
216→      conversationId: conversationRecord.id as string,
217→      messages,
218→      seeds,
219→      sidebar,
220→    };
221→
222→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
223→      workspaceId,
224→      conversationId: conversationRecord.id as string,
225→      messageCount: messages.length,
226→      seedCount: seeds.length,
227→      durationMs: elapsedMs(startedAt),
228→    });
229→
230→    return jsonResponse(payload, 200);
231→  } catch (error) {
232→    if (error instanceof HttpError) {
233→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
234→        workspaceId,
235→        statusCode: error.status,
236→      });
237→      return jsonError(error.message, error.status);
238→    }
239→
240→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
241→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
242→    return jsonError(errorText, 500);
243→  }
244→}
245→
246→async function resolveWorkspaceBootstrapConversation(
247→  deps: ServerDependencies,
248→  workspaceRecord: RecordId<"workspace", string>,
249→): Promise<RecordId<"conversation", string>> {
250→  const [onboardingRows] = await deps.surreal
251→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
252→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
253→      {
254→        workspace: workspaceRecord,
255→      },
256→    )
257→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
258→
259→  if (onboardingRows.length > 0) {
260→    return onboardingRows[0].id;
261→  }
262→
