        : config.surrealUrl.startsWith("https://")
          ? "https"
          : "http",
    surrealNamespace: config.surrealNamespace,
    surrealDatabase: config.surrealDatabase,
    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
  });
}

