    .collect<[ConversationProvenanceRow[]]>();

  const seen = new Set<string>();
  const items: ExtractionGraphContextRow[] = [];

  for (const row of rows) {
    const entityId = row.out.id as string;
    if (seen.has(entityId)) {
      continue;
    }

    const entityTable = row.out.tb;
    if (
      entityTable !== "project" &&
